import React from "react";
import {
  VerticalTimeline,
  VerticalTimelineElement,
} from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";

import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const GRADIENTS = {
  briefcaseBlack: "linear-gradient(135deg, #434343 0%, black 100%)", // para trabajos "negro-blanco"
  briefcaseYellow: "linear-gradient(135deg, #f7971e 0%, #ffd200 100%)", // para otros trabajos dorados
  briefcaseBlueGreen: "linear-gradient(135deg, #43cea2 0%, #185a9d 100%)", // otros trabajos
  briefcasePurple: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)", // otros trabajos
  universityBlue: "linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)", // para certificaciones y universidad
  cloudBlue: "linear-gradient(135deg, #0072c6 0%, #00a1f1 100%)", // para ícono cloud
};

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022 - Present",
    icon: <FaBriefcase />,
    iconBgGradient: GRADIENTS.briefcasePurple,
    contentBgGradient: GRADIENTS.briefcasePurple,
    arrowBorderColor: "#764ba2",
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021 - 2022",
    icon: <FaBriefcase />,
    iconBgGradient: GRADIENTS.briefcaseBlueGreen,
    contentBgGradient: GRADIENTS.briefcaseBlueGreen,
    arrowBorderColor: "#185a9d",
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014 - 2021",
    icon: <FaBriefcase />,
    iconBgGradient: GRADIENTS.briefcaseYellow,
    contentBgGradient: GRADIENTS.briefcaseYellow,
    arrowBorderColor: "#ffd200",
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013 - 2014",
    icon: <FaBriefcase />,
    iconBgGradient: GRADIENTS.briefcaseYellow,
    contentBgGradient: GRADIENTS.briefcaseYellow,
    arrowBorderColor: "#ffd200",
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008 - 2013",
    icon: <FaBriefcase />,
    iconBgGradient: GRADIENTS.briefcaseYellow,
    contentBgGradient: GRADIENTS.briefcaseYellow,
    arrowBorderColor: "#ffd200",
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001 - 2008",
    icon: <FaBriefcase />,
    iconBgGradient: GRADIENTS.briefcaseBlack,
    contentBgGradient: GRADIENTS.briefcaseBlack,
    arrowBorderColor: "black",
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001 - 2006",
    icon: <FaUniversity />,
    iconBgGradient: GRADIENTS.universityBlue,
    contentBgGradient: GRADIENTS.universityBlue,
    arrowBorderColor: "#3b82f6",
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
    iconBgGradient: GRADIENTS.cloudBlue,
    contentBgGradient: GRADIENTS.cloudBlue,
    arrowBorderColor: "#00a1f1",
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
    iconBgGradient: GRADIENTS.universityBlue,
    contentBgGradient: GRADIENTS.universityBlue,
    arrowBorderColor: "#3b82f6",
  },
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2023 - 2024",
    icon: <FaUniversity />,
    iconBgGradient: GRADIENTS.universityBlue,
    contentBgGradient: GRADIENTS.universityBlue,
    arrowBorderColor: "#3b82f6",
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022 - 2024",
    icon: <FaUniversity />,
    iconBgGradient: GRADIENTS.universityBlue,
    contentBgGradient: GRADIENTS.universityBlue,
    arrowBorderColor: "#3b82f6",
  },
];

// Parsear año inicial para ordenar
const parseStartYear = (dateStr) => {
  const match = dateStr.match(/^(\d{4})/);
  return match ? parseInt(match[1], 10) : 0;
};

export default function ExperienceTimeline() {
  const sortedData = [...experienceData].sort(
    (a, b) => parseStartYear(b.date) - parseStartYear(a.date)
  );

  return (
    <VerticalTimeline>
      {sortedData.map((exp, idx) => {
        const isUniversityOrCloud =
          exp.icon.type === FaUniversity || exp.icon.type === FaCloud;

        return (
          <VerticalTimelineElement
            key={idx}
            date={
              <span
                style={{
                  fontWeight: "bold",
                  color: "white",
                  fontSize: "1.1rem",
                  textShadow: "0 0 5px rgba(0,0,0,0.7)",
                }}
              >
                {exp.date}
              </span>
            }
            iconStyle={{
              background: exp.iconBgGradient,
              color: "#fff",
              boxShadow: "0 0 10px rgba(0,0,0,0.4)",
            }}
            contentStyle={{
              background: exp.contentBgGradient,
              color: "#fff",
              boxShadow: "0 4px 15px rgba(0,0,0,0.3)",
              padding: isUniversityOrCloud ? "10px 15px" : "20px",
            }}
            contentArrowStyle={{
              borderRight: `7px solid ${exp.arrowBorderColor}`,
            }}
            style={{ marginBottom: "10px", marginTop: "10px" }}
            icon={exp.icon}
          >
            <h3
              style={{
                fontSize: isUniversityOrCloud ? "1rem" : "1.3rem",
                marginBottom: 4,
              }}
            >
              {exp.title}
            </h3>
            <h4
              style={{
                fontSize: isUniversityOrCloud ? "0.85rem" : "1.1rem",
                marginTop: 0,
              }}
            >
              {exp.company}
            </h4>
          </VerticalTimelineElement>
        );
      })}
    </VerticalTimeline>
  );
}
